          {type === 'fork' && (<circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" /></circle>)}
