                  <p className="text-[#8a9db8] font-orbitron tracking-widest text-[10px] md:text-xs">
                      {isFinished ? 'SEQUENCING COMPLETE' : 'GENERATING BRACKET SEEDS...'}
                  </p>
              </div>

              {/* --- CENTRAL STAGE (Active Draw) --- */}
              {!isFinished && currentMatch && (
                  <div className="w-full max-w-4xl mb-12 relative z-20 animate-slide-in">
                      <div className="bg-[#0a1a2f]/90 border-y-2 border-[#dcb06b] relative p-8 md:p-12 flex flex-col items-center shadow-[0_0_50px_rgba(220,176,107,0.2)]">
                          {/* Tech Borders */}
                          <div className="absolute top-0 left-0 w-4 h-4 border-l-2 border-t-2 border-[#dcb06b]"></div>
