                          <div className="flex flex-col md:flex-row items-center justify-center gap-8 w-full">
                              {/* Left Side */}
                              <div className="flex-1 w-full">
                                  <RollingTeamName 
                                      targetName={currentMatch.teamA?.name || "TBD"} 
                                      isRolling={lotteryState.step === 'rolling-all'}
                                      isLocked={lotteryState.step !== 'rolling-all'}
                                      poolNames={teamNamesPool}
