                                      label="CHALLENGER A"
                                  />
                              </div>

                              {/* VS Badge */}
                              <div className="relative w-20 h-20 flex items-center justify-center shrink-0">
                                  <div className="absolute inset-0 bg-[#dcb06b] rotate-45 blur-lg opacity-40"></div>
