                                      isLocked={lotteryState.step === 'locked-B' || lotteryState.step === 'confirmed'}
                                      poolNames={teamNamesPool}
                                      color="#ef4444"
                                      label="CHALLENGER B"
                                  />
                              </div>
                          </div>
                      </div>
                  </div>
