              {/* --- CONFIRMED MATCHES LIST --- */}
              <div className="w-full max-w-5xl grid grid-cols-1 md:grid-cols-2 gap-4 pb-40">
                  {matchesToReveal.map((m, idx) => {
                      // Only show matches that are historically confirmed
                      if (!lotteryState.history.includes(idx)) return null;

                      return (
                          <div key={m.id} className="bg-[#0a1a2f]/60 border border-[#1e3a5f] p-4 flex items-center justify-between animate-slide-in clip-corner-sm">
                              <span className="text-[10px] font-orbitron text-[#4a5f78] w-20">{m.label}</span>
                              <div className="flex-1 flex items-center justify-end gap-3 text-right">
                                  <span className="font-bold text-white text-sm">{m.teamA?.name}</span>
                                  <span className="text-[#dcb06b] text-xs font-black">VS</span>
                                  <span className="font-bold text-white text-sm">{m.teamB?.name}</span>
                              </div>
                          </div>
